+    const num_bytes = first & 0x7F;
+    if (num_bytes > 4 or pos.* + num_bytes > data.len) return error.InvalidDer;
+
+    var length: usize = 0;
+    for (0..num_bytes) |_| {
+        length = (length << 8) | data[pos.*];
+        pos.* += 1;
+    }
+    return length;
+}
