+/// Parse DER integer (returns slice to the integer bytes, big-endian)
+fn parseDerInteger(data: []const u8, pos: *usize) ![]const u8 {
+    if (pos.* >= data.len or data[pos.*] != 0x02) return error.InvalidDer;
+    pos.* += 1;
