+    var i: usize = 0;
+    var j: usize = padding;
+    if (hex_len % 2 == 1) {
+        bytes[j] = try hexDigit(hex[0]);
+        i = 1;
+        j += 1;
+    }
+    while (i < hex_len) : ({
+        i += 2;
+        j += 1;
+    }) {
